import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import android.widget.Toast

class DeepLinkHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent?) {
        val data: Uri? = intent?.data
        if (data != null && data.scheme == "myapp") {
            when (data.host) {
                "profile" -> {
                    val userId = data.lastPathSegment
                    if (!userId.isNullOrEmpty()) {
                        navigateToProfile(userId)
                    } else {
                        Toast.makeText(this, "Invalid Profile ID", Toast.LENGTH_SHORT).show()
                    }
                }
                "payment" -> {
                    if (data.pathSegments.contains("confirm")) {
                        navigateToPaymentConfirmation()
                    } else {
                        Toast.makeText(this, "Invalid Payment Path", Toast.LENGTH_SHORT).show()
                    }
                }
                else -> {
                    Toast.makeText(this, "Unknown deep link", Toast.LENGTH_SHORT).show()
                }
            }
        }
    }

    private fun navigateToProfile(userId: String) {
        val intent = Intent(this, ProfileActivity::class.java)
        intent.putExtra("EXTRA_USER_ID", userId)
        startActivity(intent)
    }

    private fun navigateToPaymentConfirmation() {
        val intent = Intent(this, PaymentConfirmationActivity::class.java)
        startActivity(intent)
    }
}

